/// Opaque handle to a configured crawl engine.
///
/// Constructed via `create_engine` with an optional `CrawlConfig`.
/// Default implementations for all pluggable components are used internally.
#[derive(Clone)]
#[napi(js_name = "CrawlEngineHandle")]
pub struct JsCrawlEngineHandle {
    inner: Arc<kreuzcrawl::CrawlEngineHandle>,
}

#[napi]
impl JsCrawlEngineHandle {
    /// Stream a single-URL crawl, yielding `CrawlEvent`s as pages are processed.
    ///
    /// Returns an async stream that emits one event per crawled page, plus a
    /// terminal `Complete` event. On per-URL failure during the crawl, emits an
    /// `Error` event followed by `Complete`. The stream item type is wrapped in
    /// a `Result` to surface transport-level errors; today every emit is `Ok`.
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "crawlStream")]
    pub async fn crawl_stream(&self, req: JsCrawlStreamRequest) -> Result<CrawlStreamIterator> {
        let inner = self.inner.clone();
        let core_req: kreuzcrawl::CrawlStreamRequest = req.into();
        let (tx, rx) = tokio::sync::mpsc::channel(32);
        tokio::spawn(async move {
            use futures_util::StreamExt;
            match inner.crawl_stream(core_req).await {
                Err(e) => {
                    let _ = tx
                        .send(Err(napi::Error::new(napi::Status::GenericFailure, e.to_string())))
                        .await;
                }
                Ok(mut stream) => {
                    while let Some(chunk) = stream.next().await {
                        let item = match chunk {
                            Ok(c) => JsCrawlEvent::from(c),
                            Err(e) => {
                                let _ = tx
                                    .send(Err(napi::Error::new(napi::Status::GenericFailure, e.to_string())))
                                    .await;
                                break;
                            }
                        };
                        if tx.send(Ok(item)).await.is_err() {
                            break;
                        }
                    }
                }
            }
        });
        let iter = CrawlStreamIterator {
            receiver: Arc::new(tokio::sync::Mutex::new(rx)),
        };
        Ok(iter)
    }

    /// Stream a multi-URL crawl, yielding `CrawlEvent`s across all seeds.
    ///
    /// Returns an async stream that emits one event per crawled page across all
    /// seeds, plus terminal `Complete` and `Error` events as appropriate. The
    /// stream item type is wrapped in a `Result` to surface transport-level
    /// errors; today every emit is `Ok`.
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "batchCrawlStream")]
    pub async fn batch_crawl_stream(&self, req: JsBatchCrawlStreamRequest) -> Result<BatchCrawlStreamIterator> {
        let inner = self.inner.clone();
        let core_req: kreuzcrawl::BatchCrawlStreamRequest = req.into();
        let (tx, rx) = tokio::sync::mpsc::channel(32);
        tokio::spawn(async move {
            use futures_util::StreamExt;
            match inner.batch_crawl_stream(core_req).await {
                Err(e) => {
                    let _ = tx
                        .send(Err(napi::Error::new(napi::Status::GenericFailure, e.to_string())))
                        .await;
                }
                Ok(mut stream) => {
                    while let Some(chunk) = stream.next().await {
                        let item = match chunk {
                            Ok(c) => JsCrawlEvent::from(c),
                            Err(e) => {
                                let _ = tx
                                    .send(Err(napi::Error::new(napi::Status::GenericFailure, e.to_string())))
                                    .await;
                                break;
                            }
                        };
                        if tx.send(Ok(item)).await.is_err() {
                            break;
                        }
                    }
                }
            }
        });
        let iter = BatchCrawlStreamIterator {
            receiver: Arc::new(tokio::sync::Mutex::new(rx)),
        };
        Ok(iter)
    }
}

