impl From<JsCrawlEvent> for kreuzcrawl::CrawlEvent {
    fn from(val: JsCrawlEvent) -> Self {
        match val.type_tag.as_str() {
            "page" => Self::Page {
                result: Box::new(val.result.map(|v| v.into()).unwrap_or_default()),
            },
            "error" => Self::Error {
                url: val.url.unwrap_or_default(),
                error: val.error.unwrap_or_default(),
            },
            "complete" => Self::Complete {
                pages_crawled: val.pages_crawled.map(|v| v as usize).unwrap_or_default(),
            },
            _ => Self::Page {
                result: Default::default(),
            },
        }
    }
}

impl From<kreuzcrawl::CrawlEvent> for JsCrawlEvent {
    fn from(val: kreuzcrawl::CrawlEvent) -> Self {
        match val {
            kreuzcrawl::CrawlEvent::Page { result } => Self {
                type_tag: "page".to_string(),
                error: None,
                pages_crawled: None,
                result: Some((*result).into()),
                url: None,
            },
            kreuzcrawl::CrawlEvent::Error { url, error } => Self {
                type_tag: "error".to_string(),
                error: Some(error),
                pages_crawled: None,
                result: None,
                url: Some(url),
            },
            kreuzcrawl::CrawlEvent::Complete { pages_crawled } => Self {
                type_tag: "complete".to_string(),
                error: None,
                pages_crawled: Some(pages_crawled as i64),
                result: None,
                url: None,
            },
        }
    }
}

impl From<JsPageAction> for kreuzcrawl::PageAction {
    fn from(val: JsPageAction) -> Self {
        match val.type_tag.as_str() {
            "click" => Self::Click {
                selector: val.selector.unwrap_or_default(),
            },
            "type" => Self::TypeText {
                selector: val.selector.unwrap_or_default(),
                text: val.text.unwrap_or_default(),
            },
            "press" => Self::Press {
                key: val.key.unwrap_or_default(),
            },
            "scroll" => Self::Scroll {
                direction: val.direction.map(|v| v.into()).unwrap_or_default(),
                selector: val.selector,
                amount: val.amount,
            },
            "wait" => Self::Wait {
                milliseconds: val.milliseconds,
                selector: val.selector,
            },
            "screenshot" => Self::Screenshot {
                full_page: val.full_page,
            },
            "executeJs" => Self::ExecuteJs {
                script: val.script.unwrap_or_default(),
            },
            "scrape" => Self::Scrape,
            _ => Self::Click {
                selector: Default::default(),
            },
        }
    }
}

